  "handoff_brief": {
    "recipient": "Shaq",
    "task_context": "Implement per-API-key rate limiting middleware. Four agents have aligned on domain rules, architecture, operational requirements, and a design refinement. The core requirement is a 100-requests-per-60-second rolling window per API key, enforced via Redis using a true sliding window algorithm. Kobe identified a boundary-burst flaw in the original fixed-window-bucket design, so the implementation must use Redis sorted sets for an accurate sliding window.",
    "domain_rules": [
      {
        "rule": "Rate limit is 100 requests per 60-second rolling window per API key",
        "testable_assertion": "The 101st request within any 60-second sliding window from the same API key returns HTTP 429"
      },
      {
        "rule": "Exceeded limit returns HTTP 429 with Retry-After header",
        "testable_assertion": "The 429 response includes a Retry-After header whose value is the number of seconds until the oldest request in the window expires (not a fixed value)"
      },
      {
        "rule": "Window resets as requests age out of the 60-second sliding window",
        "testable_assertion": "After the oldest request in the window ages past 60 seconds, capacity is freed and the next request succeeds (HTTP 200)"
      },
      {
        "rule": "Rate limiter fails open when Redis is unavailable",
        "testable_assertion": "When Redis is down, all requests are allowed through (no 429s) and a redis_unavailable_total metric is incremented"
      }
    ],
    "architecture_guidance": [
      {
        "decision": "Use Redis sorted sets for a true sliding window (not fixed window counters)",
        "implementation_note": "MJ's original design used key pattern rate_limit:{api_key}:{window_start_unix} which creates fixed windows and allows burst at boundaries. Kobe flagged this. Instead: use a single sorted set per API key (key: rate_limit:{api_key}), add each request as a member with score = unix timestamp in ms, ZREMRANGEBYSCORE to evict entries older than now - 60s, then ZCARD to count. Wrap in a MULTI/EXEC or Lua script for atomicity."
      },
      {
        "decision": "Set TTL on sorted set keys to auto-expire idle keys",
        "implementation_note": "EXPIRE the sorted set key to 60 seconds on each request. This prevents unbounded memory growth from inactive API keys."
      },
      {
        "decision": "Middleware runs before all authenticated routes",
        "implementation_note": "The rate limit check must execute after authentication (so the API key is available) but before any business logic. Extract the API key from the auth context and pass it to the rate limiter."
      },
      {
        "decision": "Fail open on Redis failure",
        "implementation_note": "Wrap all Redis calls in try/catch. On any Redis exception, log a warning, increment redis_unavailable_total metric, and allow the request through. Do NOT throw or return 429."
      },
      {
        "decision": "Retry-After is dynamically computed, not a fixed value",
        "implementation_note": "Compute Retry-After as: ceiling((oldest_member_score + 60000ms - now) / 1000). This tells the caller exactly how many seconds until the first slot frees up. Use ZRANGE ... LIMIT 0 1 to get the oldest member's score."
      }
    ],
    "acceptance_criteria": [
      {
        "criterion": "101st request is rejected",
        "given": "An API key has made 100 requests in the last 60 seconds",
        "when": "A 101st request arrives from the same API key",
        "then": "HTTP 429 is returned with a Retry-After header containing seconds until the oldest request ages out"
      },
      {
        "criterion": "Window slides correctly (no boundary burst)",
        "given": "An API key made 50 requests at T=0s and 50 requests at T=30s",
        "when": "A request arrives at T=61s",
        "then": "The 50 requests from T=0s have aged out, leaving 50 in the window, so the request succeeds (HTTP 200)"
      },
      {
        "criterion": "Limit resets as requests expire",
        "given": "An API key hit the 100-request limit",
        "when": "60 seconds have elapsed since the earliest request in the current window",
        "then": "New requests succeed (HTTP 200)"
      },
      {
        "criterion": "Fail open when Redis is unavailable",
        "given": "Redis is down or unreachable",
        "when": "Any request arrives",
        "then": "The request is allowed through, and the redis_unavailable_total metric is incremented"
      },
      {
        "criterion": "Metrics are emitted",
        "given": "Rate limiting is active",
        "when": "A request is rate-limited OR Redis is unavailable",
        "then": "rate_limit_exceeded_total or redis_unavailable_total counters are incremented respectively"
      },
      {
        "criterion": "Fail-open behavior is explicitly tested",
        "given": "A test environment where Redis connectivity can be simulated as down",
        "when": "Requests are made during Redis unavailability",
        "then": "Tests verify requests pass through and the redis_unavailable_total metric increments (Kobe flagged this as mandatory)"
      }
    ],
    "terminology_alignment": [
      {
        "domain_term": "rolling window",
        "technical_term": "sliding window via Redis sorted set",
        "definition": "A continuously moving 60-second time window where each request's timestamp is tracked individually, as opposed to a fixed-bucket window that resets at discrete intervals"
      },
      {
        "domain_term": "Retry-After",
        "technical_term": "TTL of oldest sorted set member relative to window boundary",
        "definition": "HTTP response header (in seconds) telling the client when to retry. Computed dynamically from the oldest request timestamp in the sorted set, not from a fixed window expiry."
      },
      {
        "domain_term": "fail open",
        "technical_term": "catch-and-allow on Redis exception",
        "definition": "When the rate-limiting infrastructure (Redis) is unavailable, the system allows all requests through rather than blocking them. This prioritizes availability over rate enforcement."
      }
    ],
    "contradictions_resolved": [
      {
        "conflict": "MJ proposed a sliding window counter with key pattern rate_limit:{api_key}:{window_start_unix} (effectively a fixed window). Kobe identified this allows burst at window boundaries, violating Bird's 'rolling window' domain rule.",
        "resolution": "Adopted Kobe's recommendation: use Redis sorted sets with per-request timestamps for a true sliding window. This satisfies Bird's domain rule that the limit applies to any 60-second rolling period, not just aligned buckets."
      },
      {
        "conflict": "Pippen specified Retry-After should be computed from 'TTL of the current window key', which only makes sense for MJ's original fixed-window key design.",
        "resolution": "With the sorted-set approach there is no window key TTL. Retry-After is instead computed from the oldest member's score: ceil((oldest_score + 60000 - now_ms) / 1000). The intent (dynamic, not fixed) is preserved."
      }
    ],
    "open_questions": [
      "Should rate limit headers (X-RateLimit-Remaining, X-RateLimit-Limit) be included on ALL responses, not just 429s? Common API practice but not specified by Bird.",
      "Is there a need for different rate limit tiers per API key (e.g., premium keys get higher limits)? Current spec assumes a flat 100/60s for all keys.",
      "Which Redis instance should be used — existing infrastructure or a dedicated instance? Impacts fail-open blast radius if shared."
    ]
  },
  "escalations": [],
  "confidence": {
    "level": 90,
    "high_confidence_areas": [
      "Domain rules are clear and unambiguous from Bird",
      "Sorted-set sliding window is the correct algorithm — Kobe's refinement of MJ's design is well-reasoned",
      "Fail-open behavior is agreed upon by all agents",
      "Retry-After computation logic is well-defined"
    ],
    "low_confidence_areas": [
      "Pippen's Retry-After spec referenced fixed-window TTL — adapted it to sorted-set model but Pippen has not explicitly confirmed",
      "No agent specified whether rate limit info headers should appear on successful responses"
    ],
    "assumptions": [
      "Redis sorted sets are available in the project's Redis version (requires Redis 1.2+, effectively universal)",
      "The Lua script or MULTI/EXEC approach for atomicity is acceptable from a performance standpoint",
      "API key is available in the request context after authentication middleware runs"
    ]
  }
}

